# Generate PG(2,q) points as normalized nonzero vectors over Fq, for q=3
def pg_points(q, n=3):
    pts=[]
    seen=set()
    for v in itertools.product(range(q), repeat=n):
        if all(x==0 for x in v): continue
        # normalize first nonzero to 1
        first=next(i for i,x in enumerate(v) if x%q!=0)
        inv=pow(v[first], -1, q)
        norm=tuple((x*inv)%q for x in v)
        if norm not in seen:
            seen.add(norm); pts.append(norm)
    return pts
def pg_plane(q):
    pts=pg_points(q,3)
    idx={p:i for i,p in enumerate(pts)}
    def span_line(i,j):
        u=pts[i]; v=pts[j]
        s=set()
        for a in range(q):
            for b in range(q):
                if a==0 and b==0: continue
                w=tuple((a*u[t]+b*v[t])%q for t in range(3))
                first=next(t for t,x in enumerate(w) if x%q!=0)
                inv=pow(w[first], -1, q)
                norm=tuple((x*inv)%q for x in w)
                s.add(idx[norm])
        return tuple(sorted(s))
    lines=set()
    for i,j in itertools.combinations(range(len(pts)),2):
        lines.add(span_line(i,j))
    lines=sorted(lines)
    pair_line={}
    for i,j in itertools.combinations(range(len(pts)),2):
        pair_line[(i,j)]=span_line(i,j)
    # line perp under dot: nonzero vector orthogonal to all points in line
    def dotq(u,v): return sum(u[t]*v[t] for t in range(3))%q
    line_perp={}
    for L in lines:
        cand=[]
        for pi,p in enumerate(pts):
            if all(dotq(p, pts[x])==0 for x in L):
                cand.append(pi)
        line_perp[L]=cand
    return pts,lines,pair_line,line_perp
