def rank_pg_subset(sub, pts, q):
    # rank of span vectors over Fq
    import itertools
    # simple Gaussian
    mat=[list(pts[i]) for i in sub]
    if not mat: return 0
    m=[row[:] for row in mat]
    rank=0; col=0; R=len(m); C=3
    for col in range(C):
        pivot=None
        for rr in range(rank,R):
            if m[rr][col]%q:
                pivot=rr; break
        if pivot is not None:
            m[rank],m[pivot]=m[pivot],m[rank]
            inv=pow(m[rank][col]%q,-1,q)
            m[rank]=[(x*inv)%q for x in m[rank]]
            for rr in range(R):
                if rr!=rank and m[rr][col]%q:
                    factor=m[rr][col]%q
                    m[rr]=[(m[rr][c]-factor*m[rank][c])%q for c in range(C)]
            rank+=1
    return rank

