import itertools, math, random

def plucker_val(n,k,w):
    # w dict tuple sorted -> val inf
    for S in itertools.combinations(range(n), k-2):
        rest=[i for i in range(n) if i not in S]
        for quad in itertools.combinations(rest,4):
            a,b,c,d=quad
            def val(pair):
                return w.get(tuple(sorted(S+pair)), math.inf)
            terms=[val((a,b))+val((c,d)), val((a,c))+val((b,d)), val((a,d))+val((b,c))]
            m=min(terms)
            if terms.count(m)<2:
                return False,(S,quad,terms)
    return True,None

def incidence_full(n,a,b,p,q):
    # min convention
    for I in itertools.combinations(range(n), a-1):
        I=set(I)
        for J in itertools.combinations(range(n), b+1):
            J=set(J)
            idx=J-I
            if not idx: continue
            terms=[]
            for i in idx:
                terms.append(p.get(tuple(sorted(I|{i})), math.inf)+q.get(tuple(sorted(J-{i})), math.inf))
            m=min(terms)
            if terms.count(m)<2:
                return False,(tuple(sorted(I)),tuple(sorted(J)),terms, list(idx))
    return True,None

def incidence_adj(n,j,g,h):
    return incidence_full(n,j,j+1,g,h)

def higgs(n,a,b,p,q,j):
    h={}
    for B in itertools.combinations(range(n),j):
        Bset=set(B)
        best=math.inf
        for A in itertools.combinations(B,j if j<a else a):
            pass
    # formula for a<=j<=b: min p(A)+q(C) where A subset B subset C
    for B in itertools.combinations(range(n),j):
        Bset=set(B); best=math.inf
        for A in itertools.combinations(B,a):
            Aset=set(A)
            # C size b superset B
            for extra in itertools.combinations([x for x in range(n) if x not in Bset], b-j):
                C=tuple(sorted(Bset|set(extra)))
                val=p.get(tuple(sorted(A)),math.inf)+q.get(C,math.inf)
                if val<best: best=val
        h[B]=best
    return h

