def incidence_nested(n,a,b,p,q):
    for I in itertools.combinations(range(n),a-1):
        Iset=set(I)
        for J in itertools.combinations(range(n),b+1):
            Jset=set(J)
            if not Iset <= Jset: continue
            terms=[]
            for i in Jset-Iset:
                terms.append(p.get(tuple(sorted(Iset|{i})), math.inf)+q.get(tuple(sorted(Jset-{i})),math.inf))
            m=min(terms)
            if terms.count(m)<2:
                return False,(I,J,terms)
    return True,None

