def random_val(n,k,maxv=3):
    return {B:random.randrange(maxv) for B in itertools.combinations(range(n),k)}

def random_valuated_uniform(n,k,maxv=3,tries=10000):
    for _ in range(tries):
        w=random_val(n,k,maxv)
        if plucker_val(n,k,w)[0]:
            return w
    return None

def random_tropical_plucker_from_matrix(n,k,modvals=5):
    # generate k x n matrix over Puiseux exponents? tropical Plucker as min over permutations of sums entries for each submatrix (tropical Stiefel); valuated
    mat=[[random.randrange(modvals) for _ in range(n)] for __ in range(k)]
    w={}
    for B in itertools.combinations(range(n),k):
        best=math.inf
        for perm in itertools.permutations(range(k)):
            s=sum(mat[row][B[perm[row]]] for row in range(k))
            if s<best: best=s
        w[B]=best
    return w

